#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    for(int tc=0; tc<T; ++tc){
        char base[105];
        if(!fgets(base, sizeof base, stdin)) break;
        size_t len = strlen(base);
        if(len && base[len-1]=='\n') base[--len]='\0';
        int n, init;
        scanf("%d %d", &n, &init);
        getchar(); // consume newline after numbers
        for(int i=0;i<n;++i){
            printf("%s", base);
            for(int j=0;j<init+i;++j) putchar('!');
            putchar('\n');
        }
    }
    return 0;
}

