#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        base = data[idx].rstrip('\n')
        idx += 1
        n, init = map(int, data[idx].split())
        idx += 1
        for i in range(n):
            out.append(base + '!' * (init + i))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

